	('9f3e31ff-e16b-4d80-a785-50bef29025cd', 'BM.27.02', 'BẢNG KIỂM GIÁM SÁT TUÂN THỦ GÓI CHĂM SÓC VÀ DUY TRÌ ỐNG THÔNG TIỂU (MAINTENANCE BUNDLE - CAUTI)', NULL, true, true, '2026-05-30 00:39:30.655809+00', '2026-05-30 00:39:30.825007+00', 'TRUC_TIEP', '[{"id": "d7eb32db-a08b-4bfa-98a1-a7d1572b152a", "stt": 1, "ma_tc": "9001", "ghi_chu": null, "noi_dung": "Bác sĩ đánh giá lại chỉ định và sự cần thiết lưu ống thông tiểu HÀNG NGÀY và ghi rõ vào hồ sơ bệnh án [1-4].", "phan_muc": "Chỉ định", "is_active": true, "ma_csv_goc": null, "diem_toi_da": 1, "cac_lua_chon": null, "cho_phep_kpa": false, "kieu_du_lieu": "BOOLEAN", "la_then_chot": false}, {"id": "1b9ce344-6c85-4372-aac6-adb8ae5851d5", "stt": 2, "ma_tc": "9002", "ghi_chu": null, "noi_dung": "Rút ống thông tiểu ngay lập tức khi không còn chỉ định y khoa [2, 3].", "phan_muc": "Chỉ định", "is_active": true, "ma_csv_goc": null, "diem_toi_da": 1, "cac_lua_chon": null, "cho_phep_kpa": false, "kieu_du_lieu": "BOOLEAN", "la_then_chot": false}, {"id": "2f11aeb3-7ec6-47c6-9d20-12d45ef1ce3d", "stt": 3, "ma_tc": "9003", "ghi_chu": null, "noi_dung": "Thực hiện vệ sinh tay TRƯỚC VÀ SAU khi chạm vào hệ thống dẫn lưu hoặc xả túi nước tiểu [1, 2].", "phan_muc": "Chỉ định", "is_active": true, "ma_csv_goc": null, "diem_toi_da": 1, "cac_lua_chon": null, "cho_phep_kpa": false, "kieu_du_lieu": "BOOLEAN", "la_then_chot": false}, {"id": "90ceeee5-6cd6-4a75-bb23-a036bd52b4dd", "stt": 4, "ma_tc": "9004", "ghi_chu": null, "noi_dung": "Vệ sinh vùng sinh dục và xung quanh ống thông bằng xà phòng thường và nước sạch 1-2 lần/ngày và sau mỗi lần NB đại tiện [1, 2, 4, 5].", "phan_muc": "Chỉ định", "is_active": true, "ma_csv_goc": null, "diem_toi_da": 1, "cac_lua_chon": null, "cho_phep_kpa": false, "kieu_du_lieu": "BOOLEAN", "la_then_chot": false}, {"id": "4f876762-0fb1-4a81-b757-28dfd84a4ada", "stt": 5, "ma_tc": "9005", "ghi_chu": null, "noi_dung": "Bắt buộc: KHÔNG sử dụng dung dịch sát khuẩn (như Povidone-Iodine) để vệ sinh vùng sinh dục thường quy [2